  font-weight: 500;
}

/* 线索区块样式 */
.clue-list { display: flex; flex-direction: column; gap: 8px; }
.clue-item { display: flex; flex-wrap: wrap; align-items: flex-start; gap: 6px; padding: 8px 12px; border-radius: 8px; background: rgba(var(--c-bg-card), 0.6); border: 1px solid rgba(var(--c-border), 0.15); transition: all 0.2s; }
.clue-item.active { border-left: 3px solid rgb(var(--c-prim)); background: rgba(var(--c-prim), 0.06); }
.clue-item.done { border-left: 3px solid rgb(var(--c-pos)); opacity: 0.7; }
.clue-item.cold { border-left: 3px solid rgba(var(--text-main), 0.3); opacity: 0.6; }
.clue-tag { font-size: calc(10px * var(--font-scale)); font-weight: 700; padding: 2px 8px; border-radius: 12px; white-space: nowrap; flex-shrink: 0; }
.clue-tag[data-type="主线"] { background: rgba(var(--c-prim), 0.15); color: rgb(var(--c-prim)); }
.clue-tag[data-type="支线"] { background: rgba(var(--c-magic), 0.15); color: rgb(var(--c-magic)); }
.clue-tag[data-type="隐藏"] { background: rgba(var(--c-neg), 0.15); color: rgb(var(--c-neg)); }
.clue-text { flex: 1; min-width: 0; font-size: calc(12px * var(--font-scale)); color: rgb(var(--text-main)); word-break: break-all; white-space: normal; line-height: 1.5; }
.clue-status { font-size: calc(10px * var(--font-scale)); padding: 2px 8px; border-radius: 10px; font-weight: 600; white-space: nowrap; flex-shrink: 0; }
.clue-status.active { background: rgba(var(--c-prim), 0.12); color: rgb(var(--c-prim)); }
.clue-status.done { background: rgba(var(--c-pos), 0.12); color: rgb(var(--c-pos)); }
.clue-status.cold { background: rgba(var(--text-main), 0.08); color: rgba(var(--text-main), 0.5); }
.clue-care { font-size: calc(10px * var(--font-scale)); padding: 2px 8px; border-radius: 10px; white-space: nowrap; flex-shrink: 0; background: rgba(var(--c-magic), 0.08); color: rgba(var(--c-magic), 0.8); display: flex; align-items: center; gap: 4px; }
 .sw-card, .npc-card, .stage-section { transition: opacity 0.15s ease, transform 0.15s ease; } .npc-card.open .npc-body { transition: max-height 0.25s ease; } .section-folded .sw-card-body, .section-folded .stage-section-body { transition: max-height 0.2s ease, opacity 0.15s ease; } 
</style>
