<body>
<textarea id="input-buffer">$1</textarea>

<div id="app" class="app" data-theme="sakura-day" data-font="medium">
    <div class="pager" id="pager">
        <div class="pager-screen">
            <div class="pager-cell"><div class="pager-label">NPC</div><div class="pager-val" id="pg-npc">0</div></div>
            <div class="pager-divider"></div>
            <div class="pager-cell"><div class="pager-label">REC</div><div class="pager-val" id="pg-rec">0</div></div>
