            Fetcher._lastSwipeId = Fetcher.getCurrentSwipeId(); 
            Fetcher._lastChatLength = Fetcher.getChatLength(); 
            this._swipeCheckInterval = setInterval(() => { 
                const swipeChanged = Fetcher.checkSwipeChange(); 
                const lengthChanged = Fetcher.checkChatLengthChange(); 
                if (swipeChanged) { 
                    this.showSwipeIndicator(); 
                    Fetcher.forceRefresh(); 
                    this.parse().then(() => this.showUpdateIndicator('Swipe已同步')); 
                } else if (lengthChanged) { 
